CREATE TRIGGER [Global].[Line_History]ON [Global].[Line]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.LineId IS NOT NULL AND d.LineId IS NULL THEN 'I' 		WHEN i.LineId IS NOT NULL AND d.LineId IS NOT NULL THEN 'U' 		WHEN i.LineId IS NULL AND d.LineId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.LineId = d.LineId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Global_Line([LineId], [UnitId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [LineId], [UnitId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Global_Line([LineId], [UnitId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [LineId], [UnitId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND